def call_name(node: ast.expr) -> str | None:
    """Best-effort dotted name for a call target, e.g. ``pd.read_csv`` or ``clean``."""
    if isinstance(node, ast.Name):
        return node.id
    if isinstance(node, ast.Attribute):
        parts = [node.attr]
        cur: ast.expr = node.value
        while isinstance(cur, ast.Attribute):
            parts.append(cur.attr)
            cur = cur.value
        if isinstance(cur, ast.Name):
            parts.append(cur.id)
            return ".".join(reversed(parts))
        return node.attr   # base isn't a simple name (e.g. a call result) — use the method name
    return None

def visit_Call(self, node: ast.Call) -> None:
    name = call_name(node.func)
    if name:
        self.calls.append(name)
    self.generic_visit(node)

def subgraph_from(flow: Flow, start: str) -> Flow:
    """BFS from ``start`` following outgoing edges; return the reachable subgraph."""
    reachable = {start}
    frontier = [start]
    while frontier:
        cur = frontier.pop()
        for name in flow.successors(cur):
            if name not in reachable:
                reachable.add(name)
                frontier.append(name)
    sub = Flow(kind=flow.kind, entry=start)
    sub.nodes = {name: flow.nodes[name] for name in reachable if name in flow.nodes}
    sub.edges = [e for e in flow.edges if e.src in reachable and e.dst in reachable]
    return sub

def run_target(path: str | Path) -> None:
    """Execute ``path`` as ``__main__`` — as a module within its package if
    it's part of one (so relative imports resolve), else as a bare script
    (unchanged behavior for standalone files)."""
    p = Path(path).resolve()
    if not (p.parent / "__init__.py").exists():
        runpy.run_path(str(p), run_name="__main__")
        return
    root, dotted = _package_root_and_module(p)
    root_str = str(root)
    already_on_path = root_str in sys.path
    if not already_on_path:
        sys.path.insert(0, root_str)
    try:
        runpy.run_module(dotted, run_name="__main__", alter_sys=True)
    finally:
        if not already_on_path:
            try:
                sys.path.remove(root_str)
            except ValueError:
                pass

def _get_lines(file: str | None, cache: dict[str, list[str] | None]) -> list[str] | None:
    """Read+split ``file`` into lines once per :func:`render_html` call — a
    project can have many nodes per file, so caching avoids re-reading it
    from disk once per node (on top of the once-per-file parse ``_get_tree``
    already avoids)."""
    if not file:
        return None
    if file not in cache:
        try:
            cache[file] = Path(file).read_text(encoding="utf-8").splitlines()
        except OSError:
            cache[file] = None
    return cache[file]

def _snippet(
    file: str | None, lineno: int | None, lines_cache: dict[str, list[str] | None], *, context: int = 4,
) -> str:
    """A few source lines around ``lineno`` — the fallback for nodes with no
    resolvable def/class (external calls, module/package nodes)."""
    if not file or not lineno:
        return ""
    lines = _get_lines(file, lines_cache)
    if lines is None:
        return ""
    start = max(0, lineno - 1 - context)
    end = min(len(lines), lineno - 1 + context + 1)
    return "\n".join(lines[start:end])

def _get_tree(file: str | None, cache: dict[str, ast.Module | None]) -> ast.Module | None:
    """Parse ``file`` once per :func:`render_html` call — a project can have
    many nodes per file, so caching avoids re-parsing it once per node."""
    if not file:
        return None
    if file not in cache:
        try:
            cache[file] = ast.parse(Path(file).read_text(encoding="utf-8"), filename=file)
        except (OSError, SyntaxError):
            cache[file] = None
    return cache[file]

def _find_def(tree: ast.Module, lineno: int) -> ast.AST | None:
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)) and node.lineno == lineno:
            return node
    return None

def _full_source(
    file: str | None,
    lineno: int | None,
    tree_cache: dict[str, ast.Module | None],
    lines_cache: dict[str, list[str] | None],
) -> str:
    """The whole def/class body (using ``end_lineno``), not just a fixed
    context window — falls back to :func:`_snippet` when there's no
    resolvable def/class at this location."""
    tree = _get_tree(file, tree_cache)
    if tree is not None and lineno is not None:
        node = _find_def(tree, lineno)
        if node is not None and getattr(node, "end_lineno", None):
            lines = _get_lines(file, lines_cache)
            if lines is not None:
                return "\n".join(lines[node.lineno - 1 : node.end_lineno])
    return _snippet(file, lineno, lines_cache)

def _payload(flow: Flow, diagnostics: dict[str, list[dict]] | None = None) -> dict:
    tree_cache: dict[str, ast.Module | None] = {}
    lines_cache: dict[str, list[str] | None] = {}
    class_index_cache: dict[str, dict[int, ast.ClassDef]] = {}
    nodes = []
    for name, node in flow.nodes.items():
        kind = "external" if node.external else node.kind
        schema = None
        if kind == "class":
            tree = _get_tree(node.file, tree_cache)
            if tree is not None and node.lineno is not None:
                if node.file not in class_index_cache:
                    class_index_cache[node.file] = build_class_index(tree)
                schema = extract_pydantic_fields(tree, node.lineno, class_index_cache[node.file])
        nodes.append({
            "id": name,
            "label": name.rsplit(".", 1)[-1],
            "kind": kind,
            "module": node.module,
            "parent": node.parent if node.parent in flow.nodes else None,
            "file": node.file,
            "lineno": node.lineno,
            "end_lineno": _def_end_lineno(node.file, node.lineno, tree_cache),
            "calls": node.calls,
            "total_time": node.total_time,
            "full_source": _full_source(node.file, node.lineno, tree_cache, lines_cache),
            "signature": _extract_signature(node.file, node.lineno, tree_cache),
            "schema": schema,
            "type_errors": (diagnostics or {}).get(name, []),
        })
    edges = [
        {"id": f"e{i}", "source": e.src, "target": e.dst, "count": e.count}
        for i, e in enumerate(flow.edges)
    ]
    return {
        "scope": flow.scope,
        "kind": flow.kind,
        "entry": flow.entry,
        "colors": _COLORS,
        "nodes": nodes,
        "edges": edges,
    }

class Flow:
    """A directed call graph: functions as nodes, call sites as edges.

    ``edges`` is a property backed by ``_edges`` plus a same-key index and
    adjacency lists — a plain ``list[FlowEdge]`` with a linear scan per
    ``add_edge``/``successors``/``predecessors`` call is O(n) per call and
    O(n^2) overall for a large project-wide graph (thousands of edges). The
    index/adjacency structures are rebuilt whenever ``edges`` is assigned
    directly (e.g. ``sub.edges = [...]`` when building a subgraph), so both
    construction paths stay consistent.
    """

    nodes: dict[str, FlowNode] = field(default_factory=dict)
    entry: str | None = None
    kind: str = "static"   # "static" (AST) | "runtime" (traced execution)
    scope: str = "file"    # "file" (single file/runtime graph) | "project" (whole directory)
    _edges: list[FlowEdge] = field(default_factory=list, init=False, repr=False, compare=False)
    _edge_index: dict[tuple[str, str], FlowEdge] = field(default_factory=dict, init=False, repr=False, compare=False)
    _out: dict[str, list[str]] = field(default_factory=dict, init=False, repr=False, compare=False)
    _in: dict[str, list[str]] = field(default_factory=dict, init=False, repr=False, compare=False)

    @property
    def edges(self) -> list[FlowEdge]:
        return self._edges

    @edges.setter
    def edges(self, value: list[FlowEdge]) -> None:
        self._edges = value
        self._edge_index = {(e.src, e.dst): e for e in value}
        out: dict[str, list[str]] = {}
        in_: dict[str, list[str]] = {}
        for e in value:
            out.setdefault(e.src, []).append(e.dst)
            in_.setdefault(e.dst, []).append(e.src)
        self._out = out
        self._in = in_

    def add_node(self, name: str, **kwargs) -> FlowNode:
        node = self.nodes.get(name)
        if node is None:
            node = FlowNode(name=name, **kwargs)
            self.nodes[name] = node
        return node

    def add_edge(self, src: str, dst: str) -> FlowEdge:
        key = (src, dst)
        existing = self._edge_index.get(key)
        if existing is not None:
            existing.count += 1
            return existing
        edge = FlowEdge(src=src, dst=dst)
        self._edges.append(edge)
        self._edge_index[key] = edge
        self._out.setdefault(src, []).append(dst)
        self._in.setdefault(dst, []).append(src)
        return edge

    def successors(self, name: str) -> list[str]:
        return list(self._out.get(name, []))

    def predecessors(self, name: str) -> list[str]:
        return list(self._in.get(name, []))

def edges(self, value: list[FlowEdge]) -> None:
    self._edges = value
    self._edge_index = {(e.src, e.dst): e for e in value}
    out: dict[str, list[str]] = {}
    in_: dict[str, list[str]] = {}
    for e in value:
        out.setdefault(e.src, []).append(e.dst)
        in_.setdefault(e.dst, []).append(e.src)
    self._out = out
    self._in = in_

def add_node(self, name: str, **kwargs) -> FlowNode:
    node = self.nodes.get(name)
    if node is None:
        node = FlowNode(name=name, **kwargs)
        self.nodes[name] = node
    return node

def _iter_python_files(root: Path, *, include_tests: bool) -> list[Path]:
    files: list[Path] = []
    for dirpath, dirnames, filenames in os.walk(root):
        dirnames[:] = [d for d in dirnames if not _is_excluded_dir(d)]
        for fname in filenames:
            if not fname.endswith(".py"):
                continue
            if not include_tests and (fname.startswith("test_") or fname.endswith("_test.py")):
                continue
            path = Path(dirpath) / fname
            if not include_tests and "tests" in path.relative_to(root).parts[:-1]:
                continue
            files.append(path)
    return sorted(files)

def _ensure_package_chain(flow: Flow, dotted: str) -> None:
    for anc in _ancestors(dotted):
        if anc not in flow.nodes:
            parent = anc.rsplit(".", 1)[0] if "." in anc else None
            flow.add_node(anc, kind="package", parent=parent)

class _ImportCollector(ast.NodeVisitor):
    """Collect ``local name -> absolute dotted target`` for one file's imports."""

    def __init__(self, module_dotted: str, is_init: bool) -> None:
        self.module_dotted = module_dotted
        self.is_init = is_init
        self.map: dict[str, str] = {}
        self.has_star_import = False

    def visit_Import(self, node: ast.Import) -> None:
        for alias in node.names:
            if alias.asname:
                self.map[alias.asname] = alias.name
            else:
                # `import a.b.c` binds the top-level name `a`; attribute access
                # on it reconstructs the rest, so map the root to itself.
                self.map[alias.name.split(".")[0]] = alias.name.split(".")[0]

    def visit_ImportFrom(self, node: ast.ImportFrom) -> None:
        base = self._resolve_base(node)
        for alias in node.names:
            if alias.name == "*":
                # Can't resolve statically what names this introduces — any
                # call through one of them will fall through to "external"
                # rather than resolving to the real project node. Surfaced as
                # a warning (not silently dropped) so that's discoverable.
                self.has_star_import = True
                warnings.warn(
                    f"{self.module_dotted}: 'from {node.module or '.'} import *' can't be "
                    "resolved statically — calls through names it introduces will show as "
                    "external in the flow graph.",
                    stacklevel=2,
                )
                continue
            local = alias.asname or alias.name
            self.map[local] = f"{base}.{alias.name}" if base else alias.name

    def _resolve_base(self, node: ast.ImportFrom) -> str:
        if node.level == 0:
            return node.module or ""
        own_package = self.module_dotted if self.is_init else (
            self.module_dotted.rsplit(".", 1)[0] if "." in self.module_dotted else ""
        )
        parts = own_package.split(".") if own_package else []
        climb = node.level - 1
        base_parts = parts[: len(parts) - climb] if climb <= len(parts) else []
        base = ".".join(base_parts)
        if node.module:
            base = f"{base}.{node.module}" if base else node.module
        return base

def __init__(self, module_dotted: str, is_init: bool) -> None:
    self.module_dotted = module_dotted
    self.is_init = is_init
    self.map: dict[str, str] = {}
    self.has_star_import = False

def visit_Import(self, node: ast.Import) -> None:
    for alias in node.names:
        if alias.asname:
            self.map[alias.asname] = alias.name
        else:
            # `import a.b.c` binds the top-level name `a`; attribute access
            # on it reconstructs the rest, so map the root to itself.
            self.map[alias.name.split(".")[0]] = alias.name.split(".")[0]

def _resolve_base(self, node: ast.ImportFrom) -> str:
    if node.level == 0:
        return node.module or ""
    own_package = self.module_dotted if self.is_init else (
        self.module_dotted.rsplit(".", 1)[0] if "." in self.module_dotted else ""
    )
    parts = own_package.split(".") if own_package else []
    climb = node.level - 1
    base_parts = parts[: len(parts) - climb] if climb <= len(parts) else []
    base = ".".join(base_parts)
    if node.module:
        base = f"{base}.{node.module}" if base else node.module
    return base

def _resolve_project_call(called: str, *, bare_to_qual: dict[str, str], import_map: dict[str, str]) -> str | None:
    """Best-effort cross-file resolution: same-file bare name / ``self./cls.``
    method (mirrors ``static._resolve``'s exact behavior), else an imported
    symbol's absolute dotted target (validated against known nodes by the caller)."""
    if "." not in called:
        # same-file def wins over an import of the same bare name.
        return bare_to_qual.get(called) or import_map.get(called)
    rprefix, _, bare = called.rpartition(".")
    if rprefix in ("self", "cls"):
        return bare_to_qual.get(bare)
    root, _, rest = called.partition(".")
    if root in import_map:
        target = import_map[root]
        return f"{target}.{rest}" if rest else target
    return None

def _module_dependency(target: str, project_modules: set[str], own_module: str) -> str | None:
    """Longest prefix of an import target that's a known project module —
    used to build the module-level dependency graph for cycle detection."""
    parts = target.split(".")
    for i in range(len(parts), 0, -1):
        candidate = ".".join(parts[:i])
        if candidate in project_modules and candidate != own_module:
            return candidate
    return None

def _detect_import_cycles(module_imports: dict[str, set[str]]) -> list[list[str]]:
    """DFS cycle detection over the project's module import graph. Returns one
    representative cycle (module names, first repeated at the end) per back
    edge found — not exhaustive for every cycle in a strongly-connected
    component, but enough to flag the problem."""
    white, gray, black = 0, 1, 2
    color = dict.fromkeys(module_imports, white)
    stack: list[str] = []
    cycles: list[list[str]] = []

    def dfs(node: str) -> None:
        color[node] = gray
        stack.append(node)
        for neighbor in module_imports.get(node, ()):
            if neighbor not in color:
                continue
            if color[neighbor] == gray:
                idx = stack.index(neighbor)
                cycles.append([*stack[idx:], neighbor])
            elif color[neighbor] == white:
                dfs(neighbor)
        stack.pop()
        color[node] = black

    for node in list(module_imports):
        if color[node] == white:
            dfs(node)
    return cycles

def dfs(node: str) -> None:
    color[node] = gray
    stack.append(node)
    for neighbor in module_imports.get(node, ()):
        if neighbor not in color:
            continue
        if color[neighbor] == gray:
            idx = stack.index(neighbor)
            cycles.append([*stack[idx:], neighbor])
        elif color[neighbor] == white:
            dfs(neighbor)
    stack.pop()
    color[node] = black

def build_project_flow(
    root: str | Path,
    *,
    entry: str | None = None,
    include_external: bool = True,
    include_tests: bool = True,
    max_files: int | None = None,
) -> Flow:
    """Build a project-wide call-graph :class:`~agentx.flow.model.Flow` for every
    ``.py`` file under ``root`` (packages/modules/classes/functions as nodes).

    Args:
        root: Directory to walk.
        entry: If given, return only the subgraph reachable from this function
            (bare or fully module-qualified name). Raises ``ValueError`` if not found.
        include_external: Include edges to calls that don't resolve to a
            function/class defined somewhere in the project.
        include_tests: Include ``test_*.py``/``*_test.py`` files and any
            ``tests/`` directory (on by default — they're real call edges too).
        max_files: If given and the number of discovered ``.py`` files exceeds
            it, raise ``ValueError`` instead of building a graph — a guard
            against accidentally pointing at a huge/unrelated directory (e.g.
            a home directory) with no feedback until it's already scanned
            everything.
    """
    root = Path(root).resolve()
    files = _iter_python_files(root, include_tests=include_tests)
    if max_files is not None and len(files) > max_files:
        raise ValueError(
            f"{len(files)} Python files found under {root} (max_files={max_files}). "
            "Pass a higher --max-files, or point at a smaller directory."
        )

    flow = Flow(kind="static", scope="project")

    # Pass 1: parse each file once, register every node + its own import map,
    # then let the parsed tree fall out of scope — pass 2 re-parses from disk
    # instead of keeping every file's AST resident simultaneously for the
    # whole function call, so peak memory no longer scales with project size
    # (at the cost of parsing each file twice; a deliberate CPU/memory trade
    # for large projects).
    per_file: dict[Path, tuple[dict[str, str], dict[str, str], str, bool]] = {}
    # per_file[path] = (bare_to_qual, import_map, module_dotted, is_init)

    for path in files:
        try:
            source = path.read_text(encoding="utf-8")
        except (OSError, UnicodeDecodeError):
            # Unreadable (permissions) or not-actually-UTF-8-text (binary file
            # with a .py extension) — skip it rather than aborting the whole
            # project walk over one bad file.
            continue
        try:
            tree = ast.parse(source, filename=str(path))
        except SyntaxError:
            continue

        module_dotted, is_init = _module_name(path, root)
        if not module_dotted:
            module_dotted = root.name or "__root__"

        parent = module_dotted.rsplit(".", 1)[0] if "." in module_dotted else None
        _ensure_package_chain(flow, module_dotted)
        flow.add_node(module_dotted, file=str(path), lineno=1, kind="package" if is_init else "module", parent=parent)

        collector = _ProjectCollector(module_dotted)
        collector.visit(tree)
        for qual, (node_ast, kind_) in collector.items.items():
            flow.add_node(
                qual, file=str(path), lineno=getattr(node_ast, "lineno", None),
                kind=kind_, module=module_dotted, parent=collector.parents[qual],
            )

        bare_to_qual: dict[str, str] = {}
        for qual, (_, kind_) in collector.items.items():
            if kind_ == "function":
                bare_to_qual.setdefault(qual.rsplit(".", 1)[-1], qual)

        importer = _ImportCollector(module_dotted, is_init)
        importer.visit(tree)

        per_file[path] = (bare_to_qual, importer.map, module_dotted, is_init)
        # `tree`/`collector`/`importer` fall out of scope here — nothing from
        # this file's AST is retained past this iteration.

    project_modules = {module_dotted for _, _, module_dotted, _ in per_file.values()}
    module_imports: dict[str, set[str]] = {}
    for _bare_to_qual, import_map, module_dotted, _is_init in per_file.values():
        deps = {
            dep for target in import_map.values()
            if (dep := _module_dependency(target, project_modules, module_dotted)) is not None
        }
        module_imports.setdefault(module_dotted, set()).update(deps)
    for cycle in _detect_import_cycles(module_imports):
        warnings.warn(f"Circular import detected: {' -> '.join(cycle)}", stacklevel=2)

    # Pass 2: re-parse each file (now that every project-wide node is known)
    # to resolve cross-file calls into edges.
    for path, (bare_to_qual, import_map, module_dotted, _is_init) in per_file.items():
        try:
            source = path.read_text(encoding="utf-8")
            tree = ast.parse(source, filename=str(path))
        except (OSError, UnicodeDecodeError, SyntaxError):
            continue  # file changed on disk between passes — skip rather than crash

        collector = _ProjectCollector(module_dotted)
        collector.visit(tree)

        for qual, (node_ast, kind_) in collector.items.items():
            if kind_ != "function":
                continue
            calls = CallCollector()
            for stmt in node_ast.body:
                calls.visit(stmt)
            for called in calls.calls:
                resolved = _resolve_project_call(called, bare_to_qual=bare_to_qual, import_map=import_map)
                if resolved and resolved in flow.nodes:
                    flow.add_edge(qual, resolved)
                elif include_external:
                    flow.add_node(called, external=True, kind="external")
                    flow.add_edge(qual, called)

        # Module-level calls (executed at import time) — attribute to the module node.
        module_calls = CallCollector()
        for stmt in tree.body:
            if isinstance(stmt, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
                continue
            module_calls.visit(stmt)
        for called in module_calls.calls:
            resolved = _resolve_project_call(called, bare_to_qual=bare_to_qual, import_map=import_map)
            if resolved and resolved in flow.nodes:
                flow.add_edge(module_dotted, resolved)
            elif include_external:
                flow.add_node(called, external=True, kind="external")
                flow.add_edge(module_dotted, called)

    if entry:
        target = entry if entry in flow.nodes else None
        if target is None:
            global_bare_to_qual: dict[str, str] = {}
            for name, node in flow.nodes.items():
                if node.kind in ("function", "class"):
                    global_bare_to_qual.setdefault(name.rsplit(".", 1)[-1], name)
            target = global_bare_to_qual.get(entry)
        if target is None:
            raise ValueError(f"Function {entry!r} not found in {root}")
        sub = subgraph_from(flow, target)
        sub.scope = "project"
        return sub

    return flow

def _label(flow: Flow, name: str) -> str:
    node = flow.nodes.get(name)
    if flow.kind != "runtime" or node is None or not node.calls:
        return name
    plural = "" if node.calls == 1 else "s"
    return f"{name}  [{node.calls} call{plural}, {node.total_time * 1000:.1f}ms]"

def _linear_chain(flow: Flow) -> list[str] | None:
    """If the flow (from ``flow.entry``) is a simple path with no branching or
    incoming fan-in along the way, return the ordered node list; else None."""
    if not flow.entry or flow.entry not in flow.nodes:
        return None
    out = defaultdict(list)
    for e in flow.edges:
        out[e.src].append(e.dst)

    order = [flow.entry]
    seen = {flow.entry}
    cur = flow.entry
    while len(out[cur]) == 1:
        nxt = out[cur][0]
        if nxt in seen:
            break   # cycle guard
        order.append(nxt)
        seen.add(nxt)
        cur = nxt
    if len(order) >= 2 and all(len(out[n]) <= 1 for n in order):
        return order
    return None

def _roots(flow: Flow) -> list[str]:
    # Only edges from a *real* node count as "incoming" — the runtime tracer's
    # synthetic "START" pseudo-caller isn't a node, so a top-level traced call
    # must not look like it has an incoming edge.
    has_incoming = {e.dst for e in flow.edges if e.src in flow.nodes}
    roots = [n for n in flow.nodes if n not in has_incoming]
    return roots or (list(flow.nodes)[:1] if flow.nodes else [])

def _walk(name: str, children: dict, flow: Flow, lines: list[str], prefix: str, is_last: bool, visited: frozenset) -> None:
    connector = "└─ " if is_last else "├─ "
    lines.append((prefix + connector + _label(flow, name)) if prefix else _label(flow, name))
    if name in visited:
        return
    visited = visited | {name}
    kids = children.get(name, [])
    new_prefix = prefix + ("   " if is_last else "│  ")
    for i, kid in enumerate(kids):
        _walk(kid, children, flow, lines, new_prefix, i == len(kids) - 1, visited)

def render_ascii(flow: Flow) -> str:
    """A vertical arrow chain for simple linear flows, or an indented tree for
    branching ones (the shape most function-call graphs actually have)."""
    if not flow.nodes:
        return "(no functions found)"

    chain = _linear_chain(flow)
    if chain:
        lines = ["○ Start"]
        for name in chain:
            lines.append(" │")
            lines.append(" ▼")
            lines.append(_label(flow, name))
        return "\n".join(lines)

    children = defaultdict(list)
    for e in flow.edges:
        children[e.src].append(e.dst)
    roots = [flow.entry] if flow.entry else _roots(flow)
    lines: list[str] = []
    for root in roots:
        _walk(root, children, flow, lines, prefix="", is_last=True, visited=frozenset())
    return "\n".join(lines) if lines else "(empty graph)"

def _mm(name: str) -> str:
    safe = name.replace('"', "'")
    return f'{_mm_id(name)}["{safe}"]'

def render_mermaid(flow: Flow) -> str:
    """Mermaid ``graph TD`` text (paste into a .md file / VS Code / GitHub)."""
    lines = ["graph TD"]
    for e in flow.edges:
        lines.append(f"    {_mm(e.src)} --> {_mm(e.dst)}")
    if not flow.edges:
        for name in flow.nodes:
            lines.append(f"    {_mm(name)}")
    return "\n".join(lines)

def render_json(flow: Flow) -> dict:
    return {
        "kind": flow.kind,
        "entry": flow.entry,
        "nodes": [
            {
                "name": n.name, "file": n.file, "lineno": n.lineno,
                "external": n.external, "calls": n.calls, "total_time": n.total_time,
            }
            for n in flow.nodes.values()
        ],
        "edges": [{"from": e.src, "to": e.dst, "count": e.count} for e in flow.edges],
    }

def render_dot(flow: Flow) -> str:
    """Graphviz DOT text — render with ``dot -Tsvg flow.dot -o flow.svg``."""
    lines = ["digraph G {", "    rankdir=TB;"]
    for name in flow.nodes:
        label = _label(flow, name).replace('"', "'")
        lines.append(f'    "{name}" [label="{label}"];')
    for e in flow.edges:
        lines.append(f'    "{e.src}" -> "{e.dst}";')
    lines.append("}")
    return "\n".join(lines)

def get_renderer(name: str) -> RendererFn | None:
    """The renderer registered under ``name``, or ``None`` if there isn't one."""
    return _RENDERERS.get(name)

def available_renderers() -> list[str]:
    """Every currently-registered renderer name, sorted."""
    return sorted(_RENDERERS)

def _base_name(node: ast.expr) -> str | None:
    if isinstance(node, ast.Name):
        return node.id
    if isinstance(node, ast.Attribute):
        return node.attr
    return None

def _is_required(value: ast.expr | None) -> bool:
    if value is None:
        return True
    # `Field(...)` — the Pydantic convention for "required, but with extra metadata".
    if isinstance(value, ast.Call) and _base_name(value.func) == "Field" and value.args:
        first = value.args[0]
        return isinstance(first, ast.Constant) and first.value is Ellipsis
    return False

def extract_pydantic_fields(
    tree: ast.Module, lineno: int, class_index: dict[int, ast.ClassDef] | None = None,
) -> list[dict] | None:
    """If the class defined at ``lineno`` in ``tree`` looks like a Pydantic
    model (bases include ``BaseModel``/``BaseSettings``), return its
    annotated fields as ``[{"name", "type", "default", "required"}, ...]``.
    Returns ``None`` if no such class is found there.

    Args:
        class_index: an optional precomputed :func:`build_class_index` result
            — pass this when calling repeatedly for many classes in the same
            ``tree`` to avoid re-walking it each time. Built on the fly (and
            discarded) if omitted.
    """
    index = class_index if class_index is not None else build_class_index(tree)
    node = index.get(lineno)
    if node is None:
        return None
    base_names = {_base_name(b) for b in node.bases}
    if not (base_names & _PYDANTIC_BASE_NAMES):
        return None
    fields = []
    for stmt in node.body:
        if isinstance(stmt, ast.AnnAssign) and isinstance(stmt.target, ast.Name):
            fields.append({
                "name": stmt.target.id,
                "type": ast.unparse(stmt.annotation),
                "default": ast.unparse(stmt.value) if stmt.value is not None else None,
                "required": _is_required(stmt.value),
            })
    return fields

class _Run:
    def __init__(self, proc: subprocess.Popen) -> None:
        self.proc = proc
        self.queue: queue.Queue[dict] = queue.Queue()
        self.done = False
        self.finished_at: float | None = None

def build_app(flow: Flow, target_path: str | Path, *, diagnostics: dict[str, list[dict]] | None = None) -> FastAPI:
    """Build the FastAPI app for ``agentx flow --serve``. Caller binds it to
    ``127.0.0.1`` via uvicorn; this function only wires routes."""
    token = secrets.token_urlsafe(16)
    target_path = str(target_path)
    invocation_cwd = Path.cwd()
    runs: dict[str, _Run] = {}
    app = FastAPI(title="agentx flow --serve", docs_url=None, redoc_url=None)
    app.state.runs = runs  # exposed for tests/introspection, not used by any route

    def _check_token(request: Request) -> None:
        if request.query_params.get("token") != token:
            raise HTTPException(status_code=403, detail="missing or invalid token")

    @app.get("/", response_class=HTMLResponse)
    def index() -> str:
        return render_html(flow, diagnostics=diagnostics, serve=True, serve_token=token)

    def _sweep_finished_runs() -> None:
        """Drop old finished-run entries so a long `--serve` session doesn't
        accumulate a `_Run` (Popen + Queue) per click forever."""
        now = time.time()
        stale = [
            rid for rid, r in runs.items()
            if r.done and r.finished_at is not None and (now - r.finished_at) > _RUN_RETENTION_SECONDS
        ]
        for rid in stale:
            del runs[rid]

    @app.post("/api/run")
    async def start_run(request: Request) -> dict:
        _check_token(request)
        _sweep_finished_runs()
        try:
            body = await request.json()
        except Exception:  # noqa: BLE001 — empty/absent body is fine, just means "default run"
            body = {}
        command = (body or {}).get("command", "").strip()

        run_id = secrets.token_hex(8)
        shell = False
        if command:
            rewritten = _maybe_package_aware_rewrite(command, invocation_cwd)
            if rewritten is not None:
                args: str | list[str] = rewritten
            else:
                # Arbitrary command — hand it to the OS's own shell verbatim,
                # exactly like typing it in a real terminal (quoting, `&&`,
                # pipes, and "command not found" all behave the same way; the
                # latter becomes normal stderr output, not a Python exception).
                args = command
                shell = True
        else:
            args = [sys.executable, "-m", "agentx.flow._serve_runner", target_path]

        try:
            proc = subprocess.Popen(
                args, shell=shell, cwd=invocation_cwd,
                stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, bufsize=1,
            )
        except OSError as exc:
            raise HTTPException(status_code=400, detail=f"failed to start: {exc}") from exc
        run = _Run(proc)
        runs[run_id] = run
        threading.Thread(target=_run_to_completion, args=(run,), daemon=True).start()
        return {"run_id": run_id}

    @app.post("/api/save")
    async def save_node_source(request: Request) -> dict:
        """Overwrite a node's def/class body in place, from the side panel's
        editor. ``lineno``/``end_lineno`` must match what :mod:`htmlgen` sent
        for that node (the exact span ``full_source`` displayed) — this isn't
        a general file-write endpoint, just "put back what you showed me,
        edited"."""
        _check_token(request)
        body = await request.json()
        file = body.get("file")
        lineno = body.get("lineno")
        end_lineno = body.get("end_lineno")
        source = body.get("source")
        if not file or not lineno or not end_lineno or source is None:
            raise HTTPException(status_code=400, detail="file, lineno, end_lineno and source are required")
        path = Path(file)
        if not path.is_absolute():
            path = invocation_cwd / path
        if not path.is_file():
            raise HTTPException(status_code=404, detail=f"no such file: {file}")
        lines = path.read_text().splitlines(keepends=True)
        if not (1 <= lineno <= end_lineno <= len(lines)):
            raise HTTPException(status_code=400, detail="lineno/end_lineno out of range for current file")
        new_body = source if source.endswith("\n") else source + "\n"
        lines[lineno - 1 : end_lineno] = [new_body]
        path.write_text("".join(lines))
        return {"ok": True}

    @app.post("/api/stop/{run_id}")
    def stop_run(run_id: str, request: Request) -> dict:
        _check_token(request)
        run = runs.get(run_id)
        if run is None:
            raise HTTPException(status_code=404, detail="unknown run_id")
        run.proc.terminate()
        return {"ok": True}

    @app.get("/api/stream/{run_id}")
    async def stream(run_id: str, request: Request):
        _check_token(request)
        run = runs.get(run_id)
        if run is None:
            raise HTTPException(status_code=404, detail="unknown run_id")

        async def generator():
            loop = asyncio.get_running_loop()
            while True:
                # A timeout (rather than a plain blocking `queue.get()`) lets
                # this executor-thread call return on its own when the
                # browser disconnects and this coroutine is cancelled —
                # otherwise the thread would sit blocked in the pool until
                # the run happens to produce another line, potentially
                # forever for a long-running/silent subprocess.
                try:
                    event = await loop.run_in_executor(None, run.queue.get, True, 1.0)
                except queue.Empty:
                    continue
                yield {"event": "message", "data": json.dumps(event)}
                if event.get("type") in ("done", "error"):
                    break

        return EventSourceResponse(generator())

    return app

