def _pump(run: _Run, stream_name: str, pipe) -> None:
    for line in iter(pipe.readline, ""):
        line = line.rstrip("\n")
        if line.startswith(SENTINEL):
            try:
                event = json.loads(line[len(SENTINEL):])
            except json.JSONDecodeError:
                event = {"type": stream_name, "text": line, "ts": time.time()}
        else:
            event = {"type": stream_name, "text": line, "ts": time.time()}
        run.queue.put(event)
    pipe.close()

def __init__(self) -> None:
    self.functions: dict[str, ast.AST] = {}
    self._scope: list[str] = []

def build_static_flow(path: str | Path, *, entry: str | None = None, include_external: bool = True) -> Flow:
    """Build a static call-graph :class:`~agentx.flow.model.Flow` for a Python file.

    Args:
        path: Path to a ``.py`` file.
        entry: If given, return only the subgraph reachable from this function
            name (bare or dotted). Raises ``ValueError`` if not found.
        include_external: Include edges to calls that don't resolve to a
            function defined in this file (stdlib/3rd-party calls, shown as
            leaf nodes tagged ``external=True``). Set False for a local-only
            call graph.
    """
    p = Path(path)
    try:
        source = p.read_text(encoding="utf-8")
    except OSError as exc:
        raise ValueError(f"Could not read {p}: {exc}") from exc
    try:
        tree = ast.parse(source, filename=str(p))
    except SyntaxError as exc:
        raise ValueError(f"Syntax error in {p}: {exc.msg} (line {exc.lineno})") from exc

    collector = _FunctionCollector()
    collector.visit(tree)
    local_names = set(collector.functions)
    # Map bare names to their qualname (e.g. "clean_data" -> "clean_data", or
    # "clean_data" -> "MyClass.clean_data" for a method) — first match wins.
    bare_to_qual: dict[str, str] = {}
    for qual in local_names:
        bare_to_qual.setdefault(qual.rsplit(".", 1)[-1], qual)

    def _resolve(called: str) -> str | None:
        if called in local_names:
            return called
        if "." in called:
            prefix, _, bare = called.rpartition(".")
            # `self.step()` / `cls.step()` — resolve the method by its bare name.
            # Other dotted calls (e.g. `pd.read_csv`) are left as external rather
            # than risking a false-positive match against an unrelated local
            # function that happens to share the same bare name.
            if prefix in ("self", "cls"):
                return bare_to_qual.get(bare)
            return None
        return bare_to_qual.get(called)

    flow = Flow(kind="static")
    for qual, node in collector.functions.items():
        flow.add_node(qual, file=str(p), lineno=getattr(node, "lineno", None))

    for qual, node in collector.functions.items():
        calls = CallCollector()
        for stmt in node.body:
            calls.visit(stmt)
        for called in calls.calls:
            resolved = _resolve(called)
            if resolved:
                flow.add_edge(qual, resolved)
            elif include_external:
                flow.add_node(called, external=True)
                flow.add_edge(qual, called)

    # Module-level calls (outside any function/class) — captures the
    # `if __name__ == "__main__": main()` entry-point pattern.
    module_calls = CallCollector()
    for stmt in tree.body:
        if isinstance(stmt, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            continue
        module_calls.visit(stmt)
    inferred_entry: str | None = None
    for called in module_calls.calls:
        resolved = _resolve(called)
        if resolved:
            flow.add_node("__main__")
            flow.add_edge("__main__", resolved)
            inferred_entry = inferred_entry or "__main__"
        elif include_external:
            flow.add_node("__main__")
            flow.add_node(called, external=True)
            flow.add_edge("__main__", called)
            inferred_entry = inferred_entry or "__main__"

    if entry:
        target = entry if entry in flow.nodes else bare_to_qual.get(entry)
        if target is None:
            raise ValueError(f"Function {entry!r} not found in {p}")
        return subgraph_from(flow, target)

    flow.entry = inferred_entry
    return flow

def _resolve(called: str) -> str | None:
    if called in local_names:
        return called
    if "." in called:
        prefix, _, bare = called.rpartition(".")
        # `self.step()` / `cls.step()` — resolve the method by its bare name.
        # Other dotted calls (e.g. `pd.read_csv`) are left as external rather
        # than risking a false-positive match against an unrelated local
        # function that happens to share the same bare name.
        if prefix in ("self", "cls"):
            return bare_to_qual.get(bare)
        return None
    return bare_to_qual.get(called)

def get_current_flow() -> Flow:
    """Return the process-global runtime :class:`~agentx.flow.model.Flow` recorded so far."""
    return _flow

def trace(func: F | None = None, *, name: str | None = None) -> F:
    """Decorator: record every call to ``func`` into the current runtime flow.

    Args:
        name: Override the recorded node name (default: ``func.__name__``, so
            e.g. a function nested inside another function is recorded under
            its plain name, not a noisy ``outer.<locals>.inner`` qualname).
            Two differently-scoped functions sharing a name are aggregated
            into one node unless you pass an explicit ``name=`` to tell them
            apart (e.g. ``@trace(name="Pipeline.step")``).
    """

    def _decorate(fn: F) -> F:
        fn_name = name or fn.__name__

        # Generator/async-generator functions must be wrapped with generator
        # functions of our own — `fn(*args, **kwargs)` on a generator function
        # only *creates* the generator object without running any of its body,
        # so entering/exiting around that call would record ~0 elapsed time
        # and never actually trace the work done while the caller iterates it.
        # Wrapping with `yield from`/`async for` instead means _enter fires on
        # the first iteration and _exit fires once the generator is exhausted
        # (or closed/thrown into), which is what "how long did this take"
        # should mean for a generator.
        if inspect.isasyncgenfunction(fn):
            @functools.wraps(fn)
            async def _agen_wrapper(*args: Any, **kwargs: Any) -> Any:
                stack_before, start = _enter(fn_name)
                try:
                    async for item in fn(*args, **kwargs):
                        yield item
                finally:
                    _exit(fn_name, stack_before, start)
            return _agen_wrapper  # type: ignore[return-value]

        if inspect.isgeneratorfunction(fn):
            @functools.wraps(fn)
            def _gen_wrapper(*args: Any, **kwargs: Any) -> Any:
                stack_before, start = _enter(fn_name)
                try:
                    yield from fn(*args, **kwargs)
                finally:
                    _exit(fn_name, stack_before, start)
            return _gen_wrapper  # type: ignore[return-value]

        if asyncio.iscoroutinefunction(fn):
            @functools.wraps(fn)
            async def _awrapper(*args: Any, **kwargs: Any) -> Any:
                stack_before, start = _enter(fn_name)
                try:
                    return await fn(*args, **kwargs)
                finally:
                    _exit(fn_name, stack_before, start)
            return _awrapper  # type: ignore[return-value]

        @functools.wraps(fn)
        def _wrapper(*args: Any, **kwargs: Any) -> Any:
            stack_before, start = _enter(fn_name)
            try:
                return fn(*args, **kwargs)
            finally:
                _exit(fn_name, stack_before, start)
        return _wrapper  # type: ignore[return-value]

    if func is not None:
        return _decorate(func)
    return _decorate  # type: ignore[return-value]

def _decorate(fn: F) -> F:
    fn_name = name or fn.__name__

    # Generator/async-generator functions must be wrapped with generator
    # functions of our own — `fn(*args, **kwargs)` on a generator function
    # only *creates* the generator object without running any of its body,
    # so entering/exiting around that call would record ~0 elapsed time
    # and never actually trace the work done while the caller iterates it.
    # Wrapping with `yield from`/`async for` instead means _enter fires on
    # the first iteration and _exit fires once the generator is exhausted
    # (or closed/thrown into), which is what "how long did this take"
    # should mean for a generator.
    if inspect.isasyncgenfunction(fn):
        @functools.wraps(fn)
        async def _agen_wrapper(*args: Any, **kwargs: Any) -> Any:
            stack_before, start = _enter(fn_name)
